css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); border: 0; color: #fff; background: #111827; border-radius: 999px; padding: 12px 18px 12px 46px; min-width: 132px; position: relative; font: 800 14px/1 system-ui, sans-serif; box-shadow: inset 0 0 0 1px #ffffff1a, 0 12px 25px #0206173d; }
.ring { position: absolute; left: 12px; top: 50%; width: 22px; height: 22px; margin-top: -11px; border-radius: 50%; border: 3px solid color-mix(in srgb, var(--accent) 25%, transparent); border-top-color: var(--accent); animation: upload-ring calc(var(--speed) * .9) linear infinite; }
.arrow { position: absolute; left: 18px; top: 50%; translate: 0 -50%; color: var(--accent-2); animation: upload-arrow calc(var(--speed) * 1.1) ease-in-out infinite; }
.text { background: linear-gradient(90deg, var(--accent), var(--accent-2)); -webkit-background-clip: text; background-clip: text; color: transparent; }
@keyframes upload-ring { to { rotate: 360deg; } }
@keyframes upload-arrow { 50% { transform: translateY(-5px); opacity:.65; } }
